/* wms-inventory-invnmove-sql-oracle.xml - updateVaildInvnAdMoveExcelUploadList */ UPDATE TWORK_UPLOAD_IV_AD_MOVE TUM SET (TUM.ERROR_CD) = ( SELECT T.ERROR_CD FROM ( WITH T_CODE AS ( SELECT DT.CTKEY , DT.CTCDHDKEY , DT.CTCDDTKEY , DT.CTCDDTNM FROM TWORK_MST_CTCD_HD HD INNER JOIN TWORK_MST_CTCD_DT DT ON DT.CTKEY = HD.CTKEY AND DT.CTCDHDKEY = HD.CTCDHDKEY
AND HD.CTKEY = #{ctkey} AND DT.CTCDHDKEY IN ( 'ICUNITTYPECD', 'IVMOVERSNCD' ) AND DT.LAKEY = #{lakey} AND HD.DELYN = 'N' AND DT.DELYN = 'N'
)
SELECT ULHSKEY , SEQ , CASE WHEN TMP.CTKEY IS NULL THEN 'TXT_UPLOAD_VALID_CTKEY_NULL' WHEN CT.CTKEY IS NULL THEN 'TXT_UPLOAD_VALID_CTKEY_INVALID' WHEN TMP.FRLCKEY IS NULL THEN 'TXT_UPLOAD_VALID_FRLCKEY_NULL' WHEN FRLC.LCKEY IS NULL THEN 'TXT_UPLOAD_VALID_FRLCKEY_INVALID' WHEN TMP.TOLCKEY IS NULL THEN 'TXT_UPLOAD_VALID_TOLCKEY_NULL' WHEN TOLC.LCKEY IS NULL THEN 'TXT_UPLOAD_VALID_TOLCKEY_INVALID' WHEN TMP.ICKEY IS NULL THEN 'TXT_UPLOAD_VALID_ICKEY_NULL' WHEN IC.ICKEY IS NULL THEN 'TXT_UPLOAD_VALID_ICKEY_INVALID' WHEN IVAT.IVATKEY IS NULL THEN 'TXT_UPLOAD_VALID_IVATKEY_INVALID' WHEN TMP.UOM IS NULL THEN 'TXT_UPLOAD_VALID_MOVE_UOM_NULL' WHEN CD1.CTCDDTKEY IS NULL THEN 'TXT_UPLOAD_VALID_MOVE_UOM_INVALID' WHEN TMP.QTY IS NULL THEN 'TXT_UPLOAD_VALID_MOVE_QTY_NULL' WHEN TMP.QTY::TEXT !~ '^[0-9]+$' THEN 'TXT_UPLOAD_VALID_MOVE_QTY_NOT_NUMBER' WHEN TMP.QTY <= 0 THEN 'TXT_UPLOAD_VALID_MOVE_QTY_CHECK' WHEN TOLC.LCSTORGTYPECD = '20' THEN CASE WHEN TMP.PLCMCNTRNO IS NULL THEN 'TXT_UPLOAD_VALID_PLCMCNTRNO_NULL' WHEN (SELECT COALESCE(MAX(CASE IVSERIALNO WHEN 'NA' THEN '' ELSE IVSERIALNO END), TMP.PLCMCNTRNO) FROM TWORK_INFO_IVATXLC WHERE CTKEY = TMP.CTKEY AND OWKEY = TMP.OWKEY AND LCKEY = TMP.TOLCKEY AND IVATKEY = IVAT.IVATKEY GROUP BY CTKEY, OWKEY, LCKEY, IVATKEY ) <> TMP.PLCMCNTRNO THEN 'TXT_UPLOAD_VALID_PLCMCNTRNO_CHECK' END WHEN TMP.IVMOVERSNCD IS NULL THEN 'TXT_UPLOAD_VALID_IVMOVERSNCD_NULL' WHEN CD2.CTCDDTKEY IS NULL THEN 'TXT_UPLOAD_VALID_IVMOVERSNCD_INVALID' END AS ERROR_CD FROM TWORK_UPLOAD_IV_AD_MOVE TMP LEFT JOIN TWORK_MST_CT CT ON CT.CTKEY = TMP.CTKEY LEFT JOIN TWORK_MST_LC FRLC ON FRLC.CTKEY = TMP.CTKEY AND FRLC.LCKEY = TMP.FRLCKEY LEFT JOIN TWORK_MST_LC TOLC ON TOLC.CTKEY = TMP.CTKEY AND TOLC.LCKEY = TMP.TOLCKEY LEFT JOIN TWORK_MST_IC IC ON IC.CTKEY = TMP.CTKEY AND IC.OWKEY = TMP.OWKEY AND IC.ICKEY = TMP.ICKEY LEFT JOIN TWORK_INFO_IVAT IVAT ON IVAT.CTKEY = TMP.CTKEY AND IVAT.OWKEY = TMP.OWKEY AND IVAT.ICKEY = TMP.ICKEY AND COALESCE(IVAT.EXPDATE, 'NA') = COALESCE(TMP.EXPDATE, 'NA') LEFT JOIN T_CODE CD1 ON CD1.CTKEY = TMP.CTKEY AND CD1.CTCDHDKEY = 'ICUNITTYPECD' AND CD1.CTCDDTNM = TMP.UOM LEFT JOIN T_CODE CD2 ON CD2.CTKEY = TMP.CTKEY AND CD2.CTCDHDKEY = 'IVMOVERSNCD' AND CD2.CTCDDTNM = TMP.IVMOVERSNCD WHERE TMP.ULHSKEY = #{upldkey} ) T WHERE TUM.ULHSKEY = T.ULHSKEY AND TUM.SEQ = T.SEQ ) WHERE TUM.ULHSKEY = #{upldkey}

