/* wms-inventory-invnmove-sql-oracle.xml - selectInvnMoveRefSql - 로케이션 이동 조회 SQL */ SELECT * FROM ( SELECT '0' AS CHK , B.PRODUCTLOT , A.CTKEY , M.CTNAME , A.IVATKEY , A.LCKEY , A.LCKEY AS FR_LCKEY , A.ULCKEY , A.ULCKEY AS FR_ULCKEY , A.OWKEY , (SELECT OWNAME FROM TWORK_MST_OW OW WHERE OW.OWKEY = A.OWKEY) AS OWNAME , A.ICKEY , ROUND(A.TTQTY / G.ICUTQTY, 2) AS TTQTY_UNIT , ROUND(A.AVQTY / G.ICUTQTY, 2) AS AVQTY_UNIT , ROUND(A.ALQTY / G.ICUTQTY, 2) AS ALQTY_UNIT , ROUND(A.PIQTY / G.ICUTQTY, 2) AS PIQTY_UNIT , ROUND(A.PAQTY / G.ICUTQTY, 2) AS PAQTY_UNIT , ROUND(A.HOQTY / G.ICUTQTY, 2) AS HOQTY_UNIT , A.TTQTY , A.AVQTY , A.ALQTY , A.PIQTY , A.PAQTY , A.HOQTY , B.PRODUCTDATE , B.EXPIREDATE , B.IBCONFIRMDATE , B.IVATSTATUS , B.ATTRIBUTE1 , B.ATTRIBUTE2 , B.ATTRIBUTE3 , C.ERPSTLC , CASE WHEN J.LCKEY = A.LCKEY THEN '' ELSE J.LCKEY END AS TO_LCKEY , '' AS TO_ERPSTLC , '' AS TO_ULCKEY , '' AS MV_QTY , '10' AS MV_REASONTYPE , A.MV_REASONTYPE AS TO_MV_REASONTYPE , D.USE_ERPSTLC , B.UOM , B.UOM AS TO_UOM , G.ICUTQTY AS TO_UOM_ICUTQTY , E.ICUTKEY , G.ICUTQTY , E.ICNAME , E.SPEC , C.MVREASON_YN , H.ACKEY , H.ACNAME , I.URKEY , I.URKEY AS URKEY_DESC , K.ZNKEY , C.LCSTORTYPE , C.WKSTATUS , C.LCHOLDTYPE , E.SHELFLIFECODETYPE , E.LOGGRPCD , E.WEIGHT , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TWORK_INFO_IVATXLCXULC A INNER JOIN TWORK_INFO_IVAT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IVATKEY = B.IVATKEY INNER JOIN TWORK_MST_LC C ON A.CTKEY = C.CTKEY AND A.LCKEY = C.LCKEY INNER JOIN TWORK_MST_OW D ON A.OWKEY = D.OWKEY INNER JOIN TWORK_MST_IC E ON B.CTKEY = E.CTKEY AND B.OWKEY = E.OWKEY AND B.ICKEY = E.ICKEY LEFT OUTER JOIN TWORK_MST_ICUT F ON E.OWKEY = F.OWKEY AND E.CTKEY = F.CTKEY AND E.ICUTKEY = F.ICUTKEY LEFT OUTER JOIN TWORK_MST_ICUTXTYPE G ON E.OWKEY = G.OWKEY AND E.CTKEY = G.CTKEY AND E.ICUTKEY = G.ICUTKEY AND B.UOM = G.ICUTTYPE LEFT OUTER JOIN TWORK_MST_AC H ON E.CTKEY = H.CTKEY AND E.ACKEY = H.ACKEY AND E.OWKEY = H.OWKEY LEFT OUTER JOIN TWORK_MST_ACXUR I ON E.CTKEY = I.CTKEY AND E.ACKEY = I.ACKEY AND E.LOGGRPCD = I.LOGGRPCD AND E.OWKEY = I.OWKEY LEFT OUTER JOIN TWORK_MST_LCXIC J ON J.CTKEY = E.CTKEY AND J.OWKEY = E.OWKEY AND J.ICKEY = E.ICKEY INNER JOIN TWORK_MST_AR L ON C.CTKEY = L.CTKEY AND C.ARKEY = L.ARKEY INNER JOIN TWORK_MST_ZN K ON L.CTKEY = K.CTKEY AND L.ZNKEY = K.ZNKEY INNER JOIN TWORK_MST_CT M ON A.CTKEY = M.CTKEY WHERE L.WRHOUS_SE = 'GNRL' AND F.CLOSDATE >= #{sysdate} AND A.TTQTY > 0
AND #{SEARCH_CONDITION}
)

