mapper.update:
/* wms-inventory-invnmove-sql-oracle.xml - updateIvatByLcByUlcDecreQty - 재고 차감 */

	UPDATE TWORK_INFO_IVATXLCXULC 
	   SET TTQTY = TTQTY - COALESCE(#{mvqty}, 0)
		 , AVQTY = AVQTY - COALESCE(#{avqty}, 0)

		 , HOQTY = HOQTY - COALESCE(#{hoqty}, 0)
		 , IVATSTATUS = #{ivatstatus}
		 , UPDATEDATE = #{sysdate}
		 , UPDATEURKEY = #{surkey}
	 WHERE CTKEY = #{ctkey}
	   AND IVATKEY = #{ivatkey}
	   AND LCKEY = #{lckey}
	   AND ULCKEY = #{ulckey}
	   AND OWKEY = #{owkey}
	   AND ICKEY = #{ickey}

/* wms-inventory-invnmove-sql-oracle.xml - "updateIvatByLcByUlcIncreQty" - 재고 증가 */

	UPDATE TWORK_INFO_IVATXLCXULC 
	   SET TTQTY = TTQTY + COALESCE(#{mvqty}, 0)
		 , AVQTY = AVQTY + COALESCE(#{avqty}, 0)

		 , HOQTY = HOQTY + COALESCE(#{hoqty}, 0)
		 , IVATSTATUS = #{ivatstatus}
		 , MV_REASONTYPE = #{mvReasontype}
		 , UPDATEDATE = #{sysdate}
		 , UPDATEURKEY = #{surkey}
	 WHERE CTKEY = #{ctkey}
	   AND IVATKEY = #{ivatkey}
	   AND LCKEY = #{lckey}
	   AND ULCKEY = #{ulckey}
	   AND OWKEY = #{owkey}
	   AND ICKEY = #{ickey}

