mapper.insert:
	/* wms-inbound-invnmanager-sql-oracle.xml - insertIvat - 재고 속성 등록  SQL */
    	INSERT INTO TWORK_INFO_IVAT   
		(
		  CTKEY
		, IVATKEY
        , OWKEY
        , ICKEY
        , EXPIREDATE
        , ATTRIBUTE1
        , ATTRIBUTE2
        , IVATSTATUS
        , IBCONFIRMDATE
        , LOGGRPCD
        , CFQTY
        , UOM
        , NET_WGT
        , INSERTDATE
        , INSERTURKEY
        , UPDATEDATE
        , UPDATEURKEY
		)
		VALUES
		(
		  #{ctkey}
		, #{ivatkey}
		, #{owkey}
		, #{ickey}
		, #{expiredate}
		, #{attribute1}			/* TC/DC 구분 */
		, #{attribute2}			/* 일반/보세 구분  */
		, '10'
		, COALESCE(#{ibconfirmdate}, TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS'))
		, COALESCE(#{loggrpcd}, '1')
		, #{mvQty}
		, #{toUom}
		, #{netWgt}
		, (TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS'))
		, #{surkey}
		, (TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS'))
		, #{surkey}
		)

mapper.update:
	/* wms-inbound-invnmanager-sql-oracle.xml - updateIncreIvat - 재고 수정  SQL */
    	UPDATE TWORK_INFO_IVAT
		   SET CFQTY       = COALESCE(CFQTY, 0) + COALESCE(#{mvqty}, 0)
		     , NET_WGT	   = COALESCE(NET_WGT, 0) + COALESCE(#{netWgt}, 0)
		     , UPDATEDATE  = (TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS'))
		     , UPDATEURKEY = #{surkey}
		 WHERE CTKEY            = #{ctkey}
           AND OWKEY            = #{owkey}
           AND ICKEY            = #{ickey}
           AND EXPIREDATE		= #{expiredate}
           AND UOM				= #{toUom}

	/* wms-inbound-invnmanager-sql-oracle.xml - updateDecreIvat - 재고 수정  SQL */
    	UPDATE TWORK_INFO_IVAT
		   SET CFQTY       = COALESCE(CFQTY, 0) - COALESCE(#{mvQty}, 0)
		     , NET_WGT	   = COALESCE(NET_WGT, 0) - COALESCE(#{netWgt}, 0)
		     , UPDATEDATE  = (TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS'))
		     , UPDATEURKEY = #{surkey}
		 WHERE CTKEY            = #{ctkey}
           AND OWKEY            = #{owkey}
           AND ICKEY            = #{ickey}
           AND EXPIREDATE		= #{expiredate}
           AND UOM				= #{uom}

