SELECT * FROM ( SELECT A.ZNKEY ,E.LOGGRPCD ,D.LCKEY ,'' AS TO_LCKEY ,D.ULCKEY ,A.CTKEY ,E.UOM ,D.ICKEY ,E.ICNAME ,E.ICUTKEY ,E.SPEC ,D.CTKEY || ';' || 'ICUTTYPE' ||';'|| E.UOM AS UOM_DESC ,D.TTQTY / F.ICUTQTY AS TTQTY ,D.AVQTY / F.ICUTQTY AS AVQTY ,D.ALQTY / F.ICUTQTY AS ALQTY ,D.PIQTY / F.ICUTQTY AS PIQTY ,D.PAQTY / F.ICUTQTY AS PAQTY ,D.HOQTY / F.ICUTQTY AS HOQTY ,D.AVQTY / F.ICUTQTY + D.HOQTY / F.ICUTQTY AS ORAVQTY ,'' AS MV_QTY ,D.OWKEY ,(SELECT OWNAME FROM TWORK_MST_OW OW WHERE OW.OWKEY = D.OWKEY) AS OWNAME ,C.PRODUCTLOT ,C.PRODUCTDATE ,C.EXPIREDATE ,C.IBCONFIRMDATE ,D.IVATKEY ,C.IVATSTATUS ,A.CTKEY || ';' || 'IVATSTATUS' ||';'|| C.IVATSTATUS AS IVATSTATUS_DESC ,C.ATTRIBUTE1 ,D.CTKEY || ';' || 'ATTRIBUTE1' ||';'|| C.ATTRIBUTE1 AS ATTRIBUTE1_DESC ,C.ATTRIBUTE2 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE2 AS ATTRIBUTE2_DESC ,C.ATTRIBUTE3 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE3 AS ATTRIBUTE3_DESC ,B.ERPSTLC ,'10' AS MV_REASONTYPE ,D.INSERTDATE ,D.INSERTURKEY ,D.UPDATEDATE ,D.UPDATEURKEY ,F.ICUTTYPE FROM TWORK_MST_AR A INNER JOIN TWORK_MST_LC B ON A.CTKEY = B.CTKEY AND A.ARKEY = B.ARKEY INNER JOIN TWORK_INFO_IVAT C ON A.CTKEY = C.CTKEY INNER JOIN TWORK_INFO_IVATXLCXULC D ON C.CTKEY = D.CTKEY AND C.IVATKEY = D.IVATKEY AND B.LCKEY = D.LCKEY INNER JOIN TWORK_MST_IC E ON C.OWKEY = E.OWKEY AND C.CTKEY = E.CTKEY AND C.ICKEY = E.ICKEY LEFT JOIN TWORK_MST_ICUTXTYPE F ON C.OWKEY = F.OWKEY AND E.CTKEY = F.CTKEY AND E.ICUTKEY = F.ICUTKEY AND E.UOM = F.ICUTTYPE WHERE A.WRHOUS_SE = 'GNRL' --일반창고 AND C.ATTRIBUTE2 = '1' AND D.TTQTY > 0 AND (D.IVATSTATUS = '10' AND D.AVQTY > 0 OR D.IVATSTATUS = '30' AND D.HOQTY > 0 ) AND A.CTKEY = #{ctkey}
