SELECT * FROM ( SELECT A.ZNKEY ,E.LOGGRPCD ,D.LCKEY ,'' AS TO_LCKEY ,D.ULCKEY ,A.CTKEY ,E.UOM ,D.ICKEY ,E.ICUTKEY ,E.ICNAME ,E.SPEC ,D.CTKEY || ';' || 'ICUTTYPE' ||';'|| E.UOM AS UOM_DESC ,D.AVQTY / F.ICUTQTY AS AVQTY ,D.AVQTY / F.ICUTQTY AS MV_QTY ,D.OWKEY ,(SELECT OWNAME FROM TWORK_MST_OW OW WHERE OW.OWKEY = D.OWKEY) AS OWNAME ,C.PRODUCTLOT ,C.PRODUCTDATE ,C.EXPIREDATE ,C.IBCONFIRMDATE ,D.IVATKEY ,C.IVATSTATUS ,A.CTKEY || ';' || 'IVATSTATUS' ||';'|| C.IVATSTATUS AS IVATSTATUS_DESC ,C.ATTRIBUTE1 ,D.CTKEY || ';' || 'ATTRIBUTE1' ||';'|| C.ATTRIBUTE1 AS ATTRIBUTE1_DESC ,C.ATTRIBUTE2 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE2 AS ATTRIBUTE2_DESC ,C.ATTRIBUTE3 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE3 AS ATTRIBUTE3_DESC ,B.ERPSTLC ,D.INSERTDATE ,D.INSERTURKEY ,D.UPDATEDATE ,D.UPDATEURKEY ,F.ICUTTYPE FROM TWORK_MST_AR A INNER JOIN TWORK_MST_LC B ON A.CTKEY = B.CTKEY AND A.ARKEY = B.ARKEY INNER JOIN TWORK_INFO_IVAT C ON A.CTKEY = C.CTKEY INNER JOIN TWORK_INFO_IVATXLCXULC D ON C.CTKEY = D.CTKEY AND C.IVATKEY = D.IVATKEY AND B.LCKEY = D.LCKEY INNER JOIN TWORK_MST_IC E ON C.OWKEY = E.OWKEY AND C.CTKEY = E.CTKEY AND C.ICKEY = E.ICKEY LEFT JOIN TWORK_MST_ICUTXTYPE F ON C.OWKEY = F.OWKEY AND E.CTKEY = F.CTKEY AND E.ICUTKEY = F.ICUTKEY AND E.UOM = F.ICUTTYPE WHERE A.WRHOUS_SE = 'ATMC' --자동창고 AND D.AVQTY > 0 AND D.IVATSTATUS = '10' AND A.CTKEY = #{ctkey}
AND #{SEARCH_CONDITION}
)

